import React from "react";

const projects = [
  {
    title: "Customer Discount Request",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Product",
    description: `Customer Discount Request plugin for Shopware 6 allows registered users to request a price discount for large number of products. 
                  Users can choose the quantity and the discount percentage for the preferred product. Shop owners or merchants can approve or reject 
                  a discount proposal for the product. After multiple requests from users, merchants can accept a proposal. Upon accepting, users will 
                  be notified when they log in to the online shop. Each product can be configured from the shop backend to receive a price discount request.`,
    link: "https://store.shopware.com/en/brand27683468217m/customer-discount-request.html",
  },
  {
    title: "Product Review Synchronization",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Automates customer review synchronization between multiple shops when product numbers match. Ensures consistent feedback 
                  display across platforms, improving user trust.`,
  },
  {
    title: "Category Discount Plugin",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Enables shop owners to configure category-wide discounts, display discount banners, and automatically adjust pricing based on set conditions.`,
  },
  {
    title: "TitanPoint Site Optimization",
    platform: "Custom Development",
    domain: "Ecommerce",
    type: "Optimization",
    description: `Optimized multimedia by converting images to WebP, improved SEO with 'Alt' attributes, and refined CSS by removing unnecessary syntax.`,
  },
];

const Projects = () => {
  return (
    <section className="min-h-screen bg-gray-100 py-12 px-6">
      <div className="container mx-auto max-w-4xl">
        <h2 className="text-4xl font-bold text-gray-800 mb-8 text-center">My Projects</h2>
        <div className="space-y-6">
          {projects.map((project, index) => (
            <div key={index} className="bg-white p-6 rounded-lg shadow-lg border border-gray-200">
              <h3 className="text-2xl font-semibold text-gray-700">{project.title}</h3>
              <p className="text-gray-500">
                <strong>Platform:</strong> {project.platform} | <strong>Domain:</strong> {project.domain} | <strong>Type:</strong> {project.type}
              </p>
              <p className="text-gray-600 mt-2">{project.description}</p>
              {project.link && (
                <a
                  href={project.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="mt-4 inline-block bg-gradient-to-r from-blue-500 to-purple-600 text-white font-semibold py-2 px-4 rounded-lg shadow-md hover:from-purple-600 hover:to-blue-500 transition-all"
                >
                  View Project
                </a>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
